import Anthropic from '@anthropic-ai/sdk'; import chalk from 'chalk'; import { getAnthropicApiKey } from '../../utils/apiKeyManager.js'; export function getClaudeModels() { return [...CLAUDE_MODELS]; } function createClaudeClient() { const apiKey = getAnthropicApiKey(); if (!apiKey) { return null; } return new Anthropic({ apiKey: apiKey }); } export function buildClaudeOptions(optimizationSet = "error_analysis") { const baseOptions = { temperature: 0.3, max_tokens: 1024, stream: false }; const optSet = OPTIMIZATION_SETS[optimizationSet] || OPTIMIZATION_SETS["error_analysis"]; return { ...baseOptions, ...optSet }; } export async function ensureClaudeAvailable() { const client = createClaudeClient(); if (!client) { console.error(chalk.red('Claude API key not found. Please set ANTHROPIC_API_KEY in your .zshrc file.')); return false; } try { await client.messages.create({ model: 'claude-3-5-haiku-20241022', max_tokens: 1, messages: [{ role: 'user', content: 'test' }] }); return true; } catch (error) { console.error(chalk.red(`Claude API error: ${error.message}`)); return false; } } export function handleClaudeError(error) { if (error.status === 401) { return 'Invalid API key. Please check your ANTHROPIC_API_KEY in .zshrc'; } else if (error.status === 429) { return 'Rate limit exceeded. Please try again in a moment.'; } else if (error.status === 400) { return 'Invalid request. Please check your input.'; } else if (error.status >= 500) { return 'Claude API is temporarily unavailable. Please try again later.'; } else { return `Claude API error: ${error.message}`; } } export async function queryClaudeStream(prompt, model, optimizationSet = "error_analysis", onStreamStart = null) { const client = createClaudeClient(); if (!client) { throw new Error('Claude API key not available'); } try { const options = buildClaudeOptions(optimizationSet); const requestParams = { model: model, max_tokens: options.max_tokens, temperature: options.temperature, messages: [ { role: 'user', content: [ { type: 'text', text: prompt } ] } ] }; if (options.stream && optimizationSet === "error_analysis") { requestParams.stream = true; let fullResponse = ''; let firstChunkReceived = false; const stream = await client.messages.create(requestParams); for await (const chunk of stream) { if (chunk.type === 'content_block_delta' && chunk.delta?.text) { const content = chunk.delta.text; if (!firstChunkReceived && typeof onStreamStart === 'function') { onStreamStart(); firstChunkReceived = true; } fullResponse += content; process.stdout.write(chalk.gray(content)); } } process.stdout.write('
'); return fullResponse; } else { const response = await client.messages.create(requestParams); return response.content[0]?.text || ''; } } catch (error) { const errorMessage = handleClaudeError(error); console.error(chalk.red(errorMessage)); throw new Error(errorMessage); } } export async function queryClaudeStructured(prompt, model, schema, options = {}) { const client = createClaudeClient(); if (!client) { throw new Error('Claude API key not available'); } try { const defaultOptions = buildClaudeOptions("patch_generation"); const combinedOptions = { ...defaultOptions, ...options }; const structuredPrompt = `${prompt}

Please respond with valid JSON that matches this schema: ${JSON.stringify(schema)}`; const response = await client.messages.create({ model: model, max_tokens: combinedOptions.max_tokens, temperature: combinedOptions.temperature, messages: [ { role: 'user', content: [ { type: 'text', text: structuredPrompt } ] } ] }); const content = response.content[0]?.text || ''; try { return JSON.parse(content); } catch (parseError) { const jsonMatch = content.match(/```(?:json)?\s*(\{[\s\S]*\})\s*```/); if (jsonMatch) { return JSON.parse(jsonMatch[1]); } throw new Error(`Failed to parse JSON response: ${parseError.message}`); } } catch (error) { const errorMessage = handleClaudeError(error); console.error(chalk.red(errorMessage)); throw new Error(errorMessage); } } export async function queryClaudeWithTempScript(prompt, model, optimizationSet = "error_analysis", onStreamStart = null) { return await queryClaudeStream(prompt, model, optimizationSet, onStreamStart); }

import { execSync } from 'child_process'; import { promises as fs } from 'fs'; import { join, dirname } from 'path'; export function runCommand(cmd, timeout = 10000) { try { const out = execSync(`${cmd} 2>&1`, { encoding: 'utf8', timeout }); return { ok: true, output: out }; } catch (e) { return { ok: false, output: e.stdout?.toString() || e.message }; } } export function checkNetwork() { try { execSync('ping -c 1 -t 1 8.8.8.8', { stdio: 'ignore' }); return true; } catch { return false; } } export async function ensureDir(dir) { try { await fs.mkdir(dir, { recursive: true }); } catch (err) { if (err.code !== 'EEXIST') throw err; } } export async function writeDebugLog(historyArr, logPath) { await ensureDir(dirname(logPath)); const content = historyArr.map((iteration, i) => { return `=== ITERATION ${i + 1} ===

